"use client"

import * as React from "react"
import {
    IconAlertTriangle,
    IconCheck,
    IconChevronRight,
    IconClock,
    IconHome,
    IconId,
    IconMinus,
    IconUsers,
} from "@tabler/icons-react"
import {
    Alert,
    AlertDescription,
    AlertTitle,
    ApprovalWorkflow,
    Badge,
    Button,
    Card,
    CardContent,
    CardDescription,
    CardHeader,
    CardTitle,
    Checkbox,
    Container,
    DataTable,
    HStack,
    MetadataList,
    Select,
    Separator,
    SignedRecord,
    VStack,
    type ColumnDef,
    type WorkflowValue,
} from "@gunjo/ui"

import {
    ID_METHODS,
    PROCEDURE_STATUS_LABEL,
    SEED_NOTIFICATIONS,
    STAGES,
    TYPE_DESCRIPTION,
    type MoveNotification,
    type ProcedureStatus,
    type RelatedProcedure,
    type StageId,
} from "./data"

/* ------------------------------------------------------------------ */
/* Helpers                                                             */
/* ------------------------------------------------------------------ */

const STAGE_LABEL: Record<StageId, string> = Object.fromEntries(
    STAGES.map((s) => [s.id, s.name])
) as Record<StageId, string>

/** Days until (or past) a due date, relative to a fixed "today". */
const TODAY = new Date("2026-06-24")
function daysUntil(due: string): number {
    const d = new Date(due)
    return Math.round((d.getTime() - TODAY.getTime()) / 86_400_000)
}

type SlaTone = "overdue" | "soon" | "ok"
function slaTone(due: string): SlaTone {
    const n = daysUntil(due)
    if (n < 0) return "overdue"
    if (n <= 2) return "soon"
    return "ok"
}

/** Status pill that conveys meaning by icon + text, not color alone. */
function ProcedureStatusBadge({ status }: { status: ProcedureStatus }) {
    const map: Record<
        ProcedureStatus,
        { variant: React.ComponentProps<typeof Badge>["variant"]; icon: React.ReactNode }
    > = {
        required: { variant: "warning", icon: <IconAlertTriangle /> },
        guided: { variant: "info", icon: <IconChevronRight /> },
        "not-needed": { variant: "outline", icon: <IconMinus /> },
        done: { variant: "success", icon: <IconCheck /> },
    }
    const { variant, icon } = map[status]
    return (
        <Badge variant={variant} icon={icon}>
            {PROCEDURE_STATUS_LABEL[status]}
        </Badge>
    )
}

function SlaBadge({ due }: { due: string }) {
    const n = daysUntil(due)
    const tone = slaTone(due)
    if (tone === "overdue") {
        return (
            <Badge variant="destructive" icon={<IconAlertTriangle />}>
                期限超過 {Math.abs(n)}日
            </Badge>
        )
    }
    if (tone === "soon") {
        return (
            <Badge variant="warning" icon={<IconClock />}>
                残り{n}日
            </Badge>
        )
    }
    return (
        <Badge variant="outline" icon={<IconClock />}>
            残り{n}日
        </Badge>
    )
}

/* ------------------------------------------------------------------ */
/* Queue (届出一覧)                                                     */
/* ------------------------------------------------------------------ */

function Queue({
    rows,
    selectedId,
    onSelect,
}: {
    rows: MoveNotification[]
    selectedId: string
    onSelect: (id: string) => void
}) {
    const columns: ColumnDef<MoveNotification>[] = [
        {
            accessorKey: "receiptNo",
            header: "受付番号",
            cell: ({ row }) => (
                <span className="font-medium tabular-nums">{row.original.receiptNo}</span>
            ),
        },
        {
            accessorKey: "type",
            header: "種別",
            cell: ({ row }) => <Badge variant="secondary">{row.original.type}</Badge>,
        },
        {
            accessorKey: "householdHead",
            header: "世帯主",
            cell: ({ row }) => (
                <div className="min-w-0">
                    <div className="truncate font-medium text-foreground">
                        {row.original.householdHead}
                    </div>
                    <div className="truncate text-xs text-muted-foreground">
                        {row.original.householdHeadKana}
                    </div>
                </div>
            ),
        },
        {
            accessorKey: "receivedAt",
            header: "受付日",
            cell: ({ row }) => <span className="tabular-nums">{row.original.receivedAt}</span>,
        },
        {
            id: "stage",
            header: "段階",
            cell: ({ row }) =>
                row.original.status === "approved" ? (
                    <Badge variant="success" icon={<IconCheck />}>
                        受理済
                    </Badge>
                ) : row.original.status === "rejected" ? (
                    <Badge variant="destructive">却下</Badge>
                ) : (
                    <Badge variant="outline">{STAGE_LABEL[row.original.currentStageId]}</Badge>
                ),
        },
        {
            id: "sla",
            header: "処理期限",
            cell: ({ row }) =>
                row.original.status === "approved" ? (
                    <span className="text-xs text-muted-foreground">—</span>
                ) : (
                    <SlaBadge due={row.original.dueDate} />
                ),
        },
    ]

    return (
        <DataTable
            columns={columns}
            data={rows}
            filter={{ columnId: "householdHead", placeholder: "世帯主で絞り込み…" }}
            pageSize={10}
            onRowClick={(row) => onSelect(row.id)}
            getRowState={(row) => (row.id === selectedId ? "selected" : undefined)}
            labels={{
                noResults: "該当する届出はありません。",
                rowsPerPage: "表示件数",
                paginationSummary: (from, to, total) => `${total}件中 ${from}–${to}件`,
                pageSummary: (cur, tot) => `${cur} / ${tot} ページ`,
                next: "次へ",
                previous: "前へ",
                firstPage: "最初のページ",
                lastPage: "最後のページ",
                filterPlaceholder: "世帯主で絞り込み…",
            }}
            renderCard={(row) => (
                <VStack gap={2}>
                    <HStack justify="between" align="start" className="gap-2">
                        <div className="min-w-0">
                            <div className="font-medium text-foreground">{row.householdHead}</div>
                            <div className="text-xs tabular-nums text-muted-foreground">
                                {row.receiptNo}
                            </div>
                        </div>
                        <Badge variant="secondary">{row.type}</Badge>
                    </HStack>
                    <HStack gap={2} className="flex-wrap">
                        {row.status === "approved" ? (
                            <Badge variant="success" icon={<IconCheck />}>
                                受理済
                            </Badge>
                        ) : (
                            <>
                                <Badge variant="outline">{STAGE_LABEL[row.currentStageId]}</Badge>
                                <SlaBadge due={row.dueDate} />
                            </>
                        )}
                    </HStack>
                </VStack>
            )}
        />
    )
}

/* ------------------------------------------------------------------ */
/* Household members (対象世帯員)                                       */
/* ------------------------------------------------------------------ */

function HouseholdMembers({
    n,
    onToggle,
    locked,
}: {
    n: MoveNotification
    onToggle: (memberId: string) => void
    locked: boolean
}) {
    return (
        <ul className="divide-y divide-border rounded-md border" aria-label="対象世帯員一覧">
            {n.members.map((m) => (
                <li
                    key={m.id}
                    className="flex flex-wrap items-center justify-between gap-3 p-3 sm:flex-nowrap"
                >
                    <div className="flex min-w-0 items-start gap-3">
                        <Checkbox
                            checked={m.included}
                            disabled={locked || m.relation.includes("世帯主")}
                            onCheckedChange={() => onToggle(m.id)}
                            aria-label={`${m.name} をこの異動の対象に含める`}
                        />
                        <div className="min-w-0">
                            <div className="flex flex-wrap items-center gap-2">
                                <span className="font-medium text-foreground">{m.name}</span>
                                <Badge variant="outline">{m.relation}</Badge>
                            </div>
                            <div className="text-xs text-muted-foreground">
                                {m.kana}・生年月日 {m.birthDate}
                            </div>
                        </div>
                    </div>
                    <span className="shrink-0 text-xs font-medium">
                        {m.included ? (
                            <span className="inline-flex items-center gap-1 text-success-strong">
                                <IconCheck className="h-3.5 w-3.5" aria-hidden /> 対象
                            </span>
                        ) : (
                            <span className="text-muted-foreground">対象外</span>
                        )}
                    </span>
                </li>
            ))}
        </ul>
    )
}

/* ------------------------------------------------------------------ */
/* Required documents checklist (必要書類)                              */
/* ------------------------------------------------------------------ */

function DocumentsChecklist({
    n,
    onToggle,
    locked,
}: {
    n: MoveNotification
    onToggle: (docId: string) => void
    locked: boolean
}) {
    return (
        <VStack gap={3}>
            {n.documents.map((d) => (
                <div key={d.id} className="flex items-start justify-between gap-3">
                    <Checkbox
                        checked={d.checked}
                        disabled={locked}
                        onCheckedChange={() => onToggle(d.id)}
                        label={
                            <span className="flex flex-wrap items-center gap-2">
                                {d.label}
                                {d.required ? (
                                    <Badge variant="outline">必須</Badge>
                                ) : (
                                    <Badge variant="secondary">任意</Badge>
                                )}
                            </span>
                        }
                        description={d.note}
                    />
                </div>
            ))}
        </VStack>
    )
}

/* ------------------------------------------------------------------ */
/* Associated procedures checklist (関連手続き)                         */
/* ------------------------------------------------------------------ */

const PROCEDURE_STATUS_ORDER: ProcedureStatus[] = [
    "required",
    "guided",
    "done",
    "not-needed",
]

function ProceduresChecklist({
    procedures,
    onChange,
    locked,
}: {
    procedures: RelatedProcedure[]
    onChange: (id: string, status: ProcedureStatus) => void
    locked: boolean
}) {
    const outstanding = procedures.filter((p) => p.status === "required").length
    return (
        <VStack gap={3}>
            {outstanding > 0 ? (
                <Alert variant="warning">
                    <IconAlertTriangle aria-hidden />
                    <AlertTitle as="p">未案内の関連手続きが {outstanding} 件あります</AlertTitle>
                    <AlertDescription>
                        住民票更新へ進む前に、各手続きを「案内済」「完了」または「不要」に更新してください。
                    </AlertDescription>
                </Alert>
            ) : null}
            <ul className="divide-y divide-border rounded-md border" aria-label="関連手続き一覧">
                {procedures.map((p) => (
                    <li key={p.id} className="flex flex-col gap-2 p-3">
                        <div className="flex flex-wrap items-start justify-between gap-2">
                            <div className="min-w-0">
                                <div className="font-medium text-foreground">{p.label}</div>
                                <p className="text-xs text-muted-foreground">{p.description}</p>
                            </div>
                            <ProcedureStatusBadge status={p.status} />
                        </div>
                        <Select
                            aria-label={`${p.label} の手続き状況`}
                            value={p.status}
                            disabled={locked}
                            onChange={(e) => onChange(p.id, e.target.value as ProcedureStatus)}
                            className="h-8 max-w-[180px] text-sm"
                        >
                            {PROCEDURE_STATUS_ORDER.map((s) => (
                                <option key={s} value={s}>
                                    {PROCEDURE_STATUS_LABEL[s]}
                                </option>
                            ))}
                        </Select>
                    </li>
                ))}
            </ul>
        </VStack>
    )
}

/* ------------------------------------------------------------------ */
/* Detail panel                                                        */
/* ------------------------------------------------------------------ */

const CLERK = "窓口 田村"

function Detail({
    n,
    onChange,
}: {
    n: MoveNotification
    onChange: (next: MoveNotification) => void
}) {
    const stageIndex = STAGES.findIndex((s) => s.id === n.currentStageId)

    // Gating logic — what must be true to advance OUT of the current stage.
    const requiredDocsChecked = n.documents
        .filter((d) => d.required)
        .every((d) => d.checked)
    const idVerified = Boolean(n.idMethod)
    const proceduresResolved = n.procedures.every((p) => p.status !== "required")
    const isAccepted = n.status === "approved" && Boolean(n.accepted)

    let canAdvance = true
    let advanceHint: React.ReactNode = null
    if (n.currentStageId === "identity") {
        canAdvance = idVerified && requiredDocsChecked
        if (!idVerified) advanceHint = "本人確認の方法を選択してください"
        else if (!requiredDocsChecked) advanceHint = "必須書類が未チェックです"
    } else if (n.currentStageId === "review") {
        canAdvance = proceduresResolved
        if (!proceduresResolved) advanceHint = "未案内の関連手続きがあります"
    } else if (n.currentStageId === "update") {
        // 住民票更新 → 完了 requires the record to be signed first.
        canAdvance = isAccepted
        if (!isAccepted) advanceHint = "受理記録に署名してください"
    }

    const workflowValue: WorkflowValue = {
        currentStageId: n.currentStageId,
        status: n.status,
        records: n.records,
    }

    const handleWorkflowChange = (next: WorkflowValue) => {
        onChange({
            ...n,
            currentStageId: next.currentStageId as StageId,
            status: next.status ?? "in-progress",
            records: next.records ?? {},
        })
    }

    const moveDetails = [
        { label: "届出種別", value: <Badge variant="secondary">{n.type}</Badge> },
        { label: "異動日", value: n.moveDate },
        { label: "受付日", value: n.receivedAt },
        {
            label: "本人確認",
            value: n.idMethod ?? "未確認",
            description: idVerified ? undefined : "本人確認の方法が未選択です",
        },
        { label: "旧住所", value: n.fromAddress },
        { label: "新住所", value: n.toAddress },
        { label: "法定処理期限", value: <span className="inline-flex"><SlaBadge due={n.dueDate} /></span> },
    ]

    const lockedForEditing = n.status !== "in-progress"

    return (
        <VStack gap={6}>
            {/* Header */}
            <div>
                <HStack justify="between" align="start" className="flex-wrap gap-2">
                    <div className="min-w-0">
                        <p className="text-sm tabular-nums text-muted-foreground">{n.receiptNo}</p>
                        <h2 className="text-2xl font-bold tracking-tight">
                            {n.householdHead} 世帯の{n.type}
                        </h2>
                        <p className="text-sm text-muted-foreground">{n.householdHeadKana}</p>
                    </div>
                    {n.status === "approved" ? (
                        <Badge variant="success" icon={<IconCheck />}>
                            受理済
                        </Badge>
                    ) : n.status === "rejected" ? (
                        <Badge variant="destructive">却下</Badge>
                    ) : (
                        <Badge variant="outline">{STAGE_LABEL[n.currentStageId]} 段階</Badge>
                    )}
                </HStack>
                <p className="mt-2 text-sm text-muted-foreground">{TYPE_DESCRIPTION[n.type]}</p>
            </div>

            {/* Workflow */}
            <Card>
                <CardHeader>
                    <CardTitle as="h3" className="text-lg">
                        処理ワークフロー
                    </CardTitle>
                    <CardDescription>
                        受付 → 本人確認 → 異動内容確認 → 住民票更新 → 完了。各段階で担当者と時刻を記録します。
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <ApprovalWorkflow
                        stages={STAGES}
                        value={workflowValue}
                        onChange={handleWorkflowChange}
                        actor={CLERK}
                        canAdvance={canAdvance}
                        advanceHint={advanceHint}
                        now={() => new Date().toLocaleString("ja-JP")}
                        stateLabels={{
                            pending: "未着手",
                            current: "対応中",
                            approved: "完了",
                            rejected: "却下",
                            skipped: "省略",
                        }}
                        labels={{
                            advance: "次の段階へ進める",
                            finish: "完了にする",
                            sendBack: "差戻し",
                            reject: "却下",
                            sendBackTarget: "差戻し先の段階",
                            reason: "理由（差戻し・却下時は必須）",
                            reasonPlaceholder: "例：転出証明書の記載に不備があるため",
                            completed: "この届出は受理・完了しました。",
                            rejected: "この届出は却下されました。",
                        }}
                    />
                </CardContent>
            </Card>

            {/* Move details */}
            <Card>
                <CardHeader>
                    <HStack gap={2}>
                        <IconHome className="h-5 w-5 text-muted-foreground" aria-hidden />
                        <CardTitle as="h3" className="text-lg">
                            異動内容
                        </CardTitle>
                    </HStack>
                </CardHeader>
                <CardContent>
                    <MetadataList items={moveDetails} layout="horizontal" />
                </CardContent>
            </Card>

            {/* Household members */}
            <Card>
                <CardHeader>
                    <HStack gap={2} justify="between">
                        <HStack gap={2}>
                            <IconUsers className="h-5 w-5 text-muted-foreground" aria-hidden />
                            <CardTitle as="h3" className="text-lg">
                                対象世帯員
                            </CardTitle>
                        </HStack>
                        <span className="text-sm text-muted-foreground">
                            {n.members.filter((m) => m.included).length} / {n.members.length} 名が対象
                        </span>
                    </HStack>
                    <CardDescription>
                        この異動に含める世帯員を選択します。世帯主は常に対象です。
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <HouseholdMembers
                        n={n}
                        locked={lockedForEditing}
                        onToggle={(id) =>
                            onChange({
                                ...n,
                                members: n.members.map((m) =>
                                    m.id === id ? { ...m, included: !m.included } : m
                                ),
                            })
                        }
                    />
                </CardContent>
            </Card>

            {/* Identity + documents */}
            <Card>
                <CardHeader>
                    <HStack gap={2}>
                        <IconId className="h-5 w-5 text-muted-foreground" aria-hidden />
                        <CardTitle as="h3" className="text-lg">
                            本人確認・必要書類
                        </CardTitle>
                    </HStack>
                    <CardDescription>
                        本人確認の方法を選び、{n.type}に必要な書類を確認します。
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <VStack gap={4}>
                        <Select
                            label="本人確認の方法"
                            value={n.idMethod ?? ""}
                            disabled={lockedForEditing}
                            onChange={(e) =>
                                onChange({ ...n, idMethod: e.target.value || undefined })
                            }
                            description={
                                idVerified ? undefined : "本人確認が完了するまで本人確認段階を進められません。"
                            }
                        >
                            <option value="">— 未選択 —</option>
                            {ID_METHODS.map((m) => (
                                <option key={m} value={m}>
                                    {m}
                                </option>
                            ))}
                        </Select>
                        <Separator />
                        <DocumentsChecklist
                            n={n}
                            locked={lockedForEditing}
                            onToggle={(id) =>
                                onChange({
                                    ...n,
                                    documents: n.documents.map((d) =>
                                        d.id === id ? { ...d, checked: !d.checked } : d
                                    ),
                                })
                            }
                        />
                    </VStack>
                </CardContent>
            </Card>

            {/* Associated procedures */}
            <Card>
                <CardHeader>
                    <CardTitle as="h3" className="text-lg">
                        関連手続き
                    </CardTitle>
                    <CardDescription>
                        この異動に伴って案内が必要な手続きです。住民へ案内し、状況を更新してください。
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <ProceduresChecklist
                        procedures={n.procedures}
                        locked={lockedForEditing}
                        onChange={(id, status) =>
                            onChange({
                                ...n,
                                procedures: n.procedures.map((p) =>
                                    p.id === id ? { ...p, status } : p
                                ),
                            })
                        }
                    />
                </CardContent>
            </Card>

            {/* Acceptance record */}
            <Card>
                <CardHeader>
                    <CardTitle as="h3" className="text-lg">
                        受理・記録
                    </CardTitle>
                    <CardDescription>
                        住民票更新の内容を確認し、署名で受理を確定します。確定後は変更できません（追記のみ可）。
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <SignedRecord
                        signerId={CLERK}
                        value={{
                            status: n.accepted ? "signed" : "draft",
                            signedBy: n.accepted?.signedBy,
                            signedAt: n.accepted?.signedAt,
                            addenda: [],
                        }}
                        canSign={stageIndex >= STAGES.findIndex((s) => s.id === "update")}
                        onChange={(v) =>
                            onChange({
                                ...n,
                                accepted:
                                    v.status === "signed" && v.signedBy && v.signedAt
                                        ? { signedBy: v.signedBy, signedAt: v.signedAt }
                                        : undefined,
                                status:
                                    v.status === "signed" && n.status === "in-progress"
                                        ? n.status
                                        : n.status,
                            })
                        }
                        labels={{
                            draft: "受理前（下書き）",
                            signed: "受理確定済",
                            sign: "受理を確定（署名）",
                            locked: "受理確定済みのため変更できません。修正は追記で行います。",
                            addendaTitle: "追記・補正記録",
                            addendum: "追記する",
                            signedByLabel: "受理担当",
                        }}
                    >
                        {({ readOnly }) => (
                            <VStack gap={2} className="text-sm">
                                <p>
                                    {n.householdHead} 世帯（対象 {n.members.filter((m) => m.included).length} 名）の
                                    {n.type}について、住民票の記載事項を新住所
                                    「{n.toAddress}」に更新します。
                                </p>
                                <p className="text-muted-foreground">
                                    本人確認：{n.idMethod ?? "未確認"} ／ 異動日：{n.moveDate}
                                </p>
                                {!readOnly && stageIndex < STAGES.findIndex((s) => s.id === "update") ? (
                                    <p className="text-xs text-warning">
                                        ※「住民票更新」段階まで進むと署名できます。
                                    </p>
                                ) : null}
                            </VStack>
                        )}
                    </SignedRecord>
                </CardContent>
            </Card>
        </VStack>
    )
}

/* ------------------------------------------------------------------ */
/* Page                                                                */
/* ------------------------------------------------------------------ */

export default function ResidentMovePage() {
    const [rows, setRows] = React.useState<MoveNotification[]>(SEED_NOTIFICATIONS)
    const [selectedId, setSelectedId] = React.useState<string>(SEED_NOTIFICATIONS[0].id)

    const selected = rows.find((r) => r.id === selectedId) ?? rows[0]

    const updateSelected = (next: MoveNotification) => {
        setRows((prev) => prev.map((r) => (r.id === next.id ? next : r)))
    }

    const overdue = rows.filter(
        (r) => r.status === "in-progress" && slaTone(r.dueDate) === "overdue"
    ).length

    return (
        <main className="min-h-screen bg-muted/20 py-6">
            <Container size="2xl">
                <VStack gap={6}>
                    <header>
                        <p className="text-sm text-muted-foreground">中央区役所 住民課・窓口</p>
                        <h1 className="text-3xl font-bold tracking-tight">住民異動届 処理</h1>
                        <p className="mt-1 text-sm text-muted-foreground">
                            転入・転出・転居・世帯主変更の届出を受け付け、本人確認・関連手続きの案内・住民票更新を行います。
                        </p>
                    </header>

                    {overdue > 0 ? (
                        <Alert variant="destructive">
                            <IconAlertTriangle aria-hidden />
                            <AlertTitle as="p">処理期限を超過した届出が {overdue} 件あります</AlertTitle>
                            <AlertDescription>
                                法定処理期限を過ぎた届出は優先的に処理してください。
                            </AlertDescription>
                        </Alert>
                    ) : null}

                    <div className="grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,440px)_minmax(0,1fr)]">
                        {/* Queue */}
                        <section aria-label="届出一覧" className="min-w-0">
                            <Card>
                                <CardHeader>
                                    <CardTitle as="h2" className="text-lg">
                                        届出一覧
                                    </CardTitle>
                                    <CardDescription>
                                        行を選択すると右側で処理できます。
                                    </CardDescription>
                                </CardHeader>
                                <CardContent>
                                    <Queue
                                        rows={rows}
                                        selectedId={selectedId}
                                        onSelect={setSelectedId}
                                    />
                                </CardContent>
                            </Card>
                        </section>

                        {/* Detail */}
                        <section aria-label="処理" className="min-w-0">
                            <Detail n={selected} onChange={updateSelected} />
                        </section>
                    </div>
                </VStack>
            </Container>
        </main>
    )
}
